import{n as e,t}from"./jsx-runtime-DTJ6URaS.js";import{n,t as r}from"./PsychedelicBackground-DuBJkzT7.js";e();var i=t(),a=()=>(0,i.jsx)(r,{children:(0,i.jsxs)(n,{title:`3 Ways a Senior Thinks`,shortRef:`senior`,children:[(0,i.jsx)(`p`,{children:`A senior is supposed to know more than a junior—needing to look less up, a better intuition for effective solutions, and knows more nuance of tech.`}),(0,i.jsxs)(`p`,{children:[`Everyone's aware of the expected technical `,(0,i.jsx)(`i`,{children:`skill`}),` difference. What's less discussed is the different ways a junior is supposed to `,(0,i.jsx)(`i`,{children:`think`}),`.`]}),(0,i.jsx)(`h3`,{children:`1. Don't make it harder than it has to be`}),(0,i.jsx)(`p`,{children:`This is broad (and that's on purpose). For example: why would you recreate a library when an external one works just fine? A junior (or newly-promoted senior) wants to validate their own skills. An experienced senior will take a sufficiently-proven pre-made library every time.`}),(0,i.jsx)(`p`,{children:`On a more technical angle, you might remember this as the DRY principle. In the same you'll encapsulate and abstract away repeatable logic, do it again on the meta level and don't repeat something you can freely borrow from someone else.`}),(0,i.jsxs)(`p`,{children:[`Ironically, insecurity about using something you yourself didn't make will make you appear `,(0,i.jsx)(`i`,{children:`less`}),` senior, not more. Meanwhile, the smartest thing you can do is not create unnecessary work for yourself.`]}),(0,i.jsx)(`h2`,{children:`2. Proliferating Knowledge and Ability`}),(0,i.jsx)(`p`,{children:`Let's say there's a critical feature on your team's app. You built it, or are the only one who knows how to maintain it. Great, you've got incredible job security, right?`}),(0,i.jsxs)(`p`,{children:[`Yeah, you do. However, `,(0,i.jsx)(`i`,{children:`half`}),` of your role is now to make sure your team can manage it without you.`]}),(0,i.jsxs)(`p`,{children:[`Get familiar with `,(0,i.jsx)(`i`,{children:`The Bus Test`}),` (or the less morbid version, the `,(0,i.jsx)(`i`,{children:`The Lottery Test`}),`). If someone on your team got hit by a bus (or won the lottery and disappeared), is there any part of your infrastructure that relies on them? Any access keys in their hands only, or a piece of code only they understand?`]}),(0,i.jsx)(`p`,{children:`If that exists for ANYONE on the team, even just some helper utilities the junior built, make a plan to proliferate it. One day, someone is going to quit or move on, and they won't be interested in documenting their knowledge when that day comes.`}),(0,i.jsx)(`h3`,{children:`3. Give your opinion boldly`}),(0,i.jsx)(`p`,{children:`Seniors are supposed to be domain expert. Typically you're not just a vague "senior" but a senior in something specific. Half of what you may speak on may not even be a specific technology, but maybe an approach, an architectural decision, or just a team practice.`}),(0,i.jsxs)(`p`,{children:[`The entire point of senior culturally is `,(0,i.jsx)(`b`,{children:`someone who can be trusted`}),`. If you're trusted, then speak! It's not only encouraged, but a requirement of your title.`]}),(0,i.jsx)(`p`,{children:`You never need to put someone else down to give your opinion. Even if you don't like their ideas, there is never a need to be rude about it. Software development is a beautiful area of life where it really is about making a solid, logic-based argument for your interests. No one likes an asshole. The good news is you can be bold your entire life without being one.`}),(0,i.jsx)(`p`,{children:`A senior leads by making things easier for the team, making the team better and more knowledgeable, and gives strong opinions when the time comes. Once you have the role, embody it well.`})]})});export{a as default};